const badgeColor = (b) => ({ Bestseller: "#1e7e34", Hot: "#e05c1a", Popular: "#1a6e8a", New: "#b8930a", Organic: "#2d7a3a", Snack: "#7a3a8a" }[b] || "#1e7e34");

// Route any image URL through a CORS proxy so hotlink-protected sources (iStock, Getty, etc.) display correctly.
// A cache-busting param is derived from the URL itself so the browser always re-fetches when the URL changes in code.
const proxyImg = (url) => {
  if (!url) return "";
  if (url.startsWith("/") || url.startsWith("data:")) return url;
  // Hash the url string into a short numeric fingerprint so changing the URL in code always busts the cache
  const bust = url.split("").reduce((acc, c) => (acc * 31 + c.charCodeAt(0)) & 0xfffffff, 0);
  return `https://images.weserv.nl/?url=${encodeURIComponent(url)}&w=1600&fit=cover&_cb=${bust}`;
};

